                  <Icon size={14} className={isActive ? 'text-rose-600' : 'opacity-70'} strokeWidth={3} />
                  <span>{item.label}</span>
                </button>
              );
            })}
          </nav>

          {/* Mobile Menu Button (Placeholder for functionality if needed later) */}
          <div className="lg:hidden">
             <div className="w-10 h-10 bg-white rounded-xl border border-slate-200 flex items-center justify-center shadow-sm">
                <div className="flex flex-col gap-1">
                    <span className="w-4 h-0.5 bg-slate-800 rounded-full"></span>
                    <span className="w-4 h-0.5 bg-slate-800 rounded-full"></span>
                </div>
             </div>
          </div>

      </div>
    </header>
  );
};

export default Header;

import React from 'react';
import { Layers, Brain, BookText, Map as MapIcon, Wand2 } from 'lucide-react';
import { AppMode } from '../types';

interface MobileNavigationProps {
