  const navItems = [
    { mode: AppMode.FLASHCARDS, label: 'Cards', icon: Layers },
    { mode: AppMode.ATLAS, label: 'Atlas', icon: MapIcon },
    { mode: AppMode.QUIZ, label: 'Exam', icon: Brain },
