import { questions as ch13 } from './hooks/data_ch13';
import { questions as ch14 } from './hooks/data_ch14';
import { questions as ch15 } from './hooks/data_ch15';
import { questions as ch16 } from './hooks/data_ch16';
import { questions as ch17 } from './hooks/data_ch17';

import { Trash2, Activity, ChevronRight, Play, BookOpen, Stethoscope, HeartPulse } from 'lucide-react';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(() => {
    return localStorage.getItem('ot_has_started') === 'true';
  });

  // PERSISTENCE: Load last mode or default to Flashcards
  const [currentMode, setCurrentMode] = useState<AppMode>(() => {
    const savedMode = localStorage.getItem('ot_current_mode');
    return (savedMode as AppMode) || AppMode.FLASHCARDS;
  });

  const [isHeaderVisible, setIsHeaderVisible] = useState(true);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // SAVE EFFECTS
  useEffect(() => {
    localStorage.setItem('ot_current_mode', currentMode);
  }, [currentMode]);

  useEffect(() => {
    localStorage.setItem('ot_has_started', String(hasStarted));
  }, [hasStarted]);

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  // --- ULTIMATE DATA ENGINE ---
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    const sources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...ch12, ...ch13, ...ch14, ...ch15, ...ch16, ...ch17,
        ...userVault
    ];

    const categoryAnswerPools: Record<string, string[]> = {};
    sources.forEach(q => {
        if (!categoryAnswerPools[q.category]) categoryAnswerPools[q.category] = [];
        if (q.answerText && q.answerText.length < 120 && !q.answerText.toLowerCase().includes('all of the above')) {
            categoryAnswerPools[q.category].push(q.answerText);
        }
    });

    sources.forEach(q => {
        // FILTER REMOVED: All questions are now allowed, regardless of quality heuristics
        if (!seenIds.has(q.id)) {
            let finalOptions = q.options ? [...q.options] : [];

            // Auto-Generate Options if missing (Safety Net)
            if (finalOptions.length < 2) {
                const pool = categoryAnswerPools[q.category] || [];
                const randomDistractors = pool
                    .filter(a => a !== q.answerText)
                    .sort(() => 0.5 - Math.random())
                    .slice(0, 3);

                finalOptions = [q.answerText, ...randomDistractors];
                if (finalOptions.length < 2) {
                    finalOptions = [q.answerText, "None of the above", "All of the above", "Structure not visible"];
                }
                // Shuffle newly generated options
                finalOptions.sort(() => 0.5 - Math.random());
            }

            // Ensure correct answer is always in options
            if (!finalOptions.includes(q.answerText)) {
                finalOptions[0] = q.answerText;
            }

            uniqueQuestions.push({ ...q, options: finalOptions });
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  if (!hasStarted) {
    return (
      <div className="min-h-[100dvh] w-full bg-slate-50 flex flex-col items-center justify-center p-6 relative overflow-hidden font-sans text-slate-900">
         {/* Tidy Background */}
         <div className="absolute inset-0 bg-white"></div>
         <div className="absolute top-0 left-0 right-0 h-[60vh] bg-slate-50 rounded-b-[4rem] z-0"></div>

         <div className="relative z-10 w-full max-w-md mx-auto flex flex-col items-center text-center space-y-10 animate-fade-in">

            {/* Logo Section */}
            <div className="w-28 h-28 bg-white rounded-3xl shadow-xl shadow-slate-200 flex items-center justify-center relative cursor-pointer hover:scale-105 transition-transform duration-500" onClick={() => setHasStarted(true)}>
                <div className="absolute inset-0 bg-gradient-to-br from-rose-50 to-slate-50 rounded-3xl opacity-50"></div>
                <HeartPulse size={56} className="text-rose-500 relative z-10" strokeWidth={1.5} />
            </div>

            {/* Typography */}
            <div className="space-y-3">
               <span className="inline-block px-3 py-1 rounded-full bg-slate-100 text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] border border-slate-200">
                  Occupational Therapy
               </span>
               <h1 className="text-4xl md:text-5xl font-black text-slate-900 tracking-tight leading-tight font-display">
                  Anatomy <span className="text-rose-500">&</span><br/>Physiology
               </h1>
               <p className="text-slate-400 font-medium text-sm max-w-xs mx-auto leading-relaxed">
                  Professional study suite v.5.5
               </p>
            </div>

            {/* Action */}
            <div className="w-full space-y-6">
                <button 
                  onClick={() => setHasStarted(true)}
                  className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs shadow-lg hover:bg-rose-600 hover:shadow-rose-200 transition-all transform active:scale-95 flex items-center justify-center gap-3"
                >
                     <span>Start Session</span>
                     <ChevronRight size={14} />
                </button>

                <div className="flex justify-center items-center gap-8 text-slate-300">
                    <div className="flex flex-col items-center gap-1.5">
                        <BookOpen size={18} />
                        <span className="text-[9px] font-bold uppercase tracking-widest">{allQuestions.length} Items</span>
                    </div>
                    <div className="w-px h-8 bg-slate-200"></div>
                    <div className="flex flex-col items-center gap-1.5">
                        <Stethoscope size={18} />
                        <span className="text-[9px] font-bold uppercase tracking-widest">Clinical</span>
                    </div>
                </div>
            </div>
         </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col font-sans text-slate-900 overflow-hidden fixed inset-0 bg-slate-50">
      {isHeaderVisible && (
        <Header currentMode={currentMode} onModeChange={(m) => setCurrentMode(m)} />
      )}

      {/* Main Content Area */}
      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isHeaderVisible ? 'pt-4 md:pb-6 max-w-7xl px-0 md:px-6' : 'max-w-full'}`}>

        <div className={`w-full h-full rounded-t-[2.5rem] md:rounded-[2.5rem] overflow-hidden shadow-2xl border border-white/50 bg-white/80 backdrop-blur-xl relative z-10 transition-all duration-700 ${!isHeaderVisible ? 'rounded-none border-none bg-white' : ''}`}>

            {currentMode === AppMode.FLASHCARDS && (
              <div className="w-full h-full animate-fade-in pb-40 md:pb-0">
                <Flashcards data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.ATLAS && (
              <div className="w-full h-full animate-fade-in pb-40 md:pb-0">
                <InteractiveAtlas data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.QUIZ && (
              <div className="w-full h-full animate-scale-in pb-40 md:pb-0">
                <Quiz 
                  data={allQuestions} 
                  toggleHeader={setIsHeaderVisible} 
                />
              </div>
            )}

            {currentMode === AppMode.LIST && (
              <div className="w-full h-full overflow-y-auto px-4 py-6 custom-scrollbar pb-40 md:pb-6 animate-fade-in">
                <QuestionList 
                  data={allQuestions}
                />
                {userVault.length > 0 && (
                    <div className="flex justify-center p-12 pb-32">
                    <button onClick={() => confirm("Reset user data?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors flex items-center gap-2">
                        <Trash2 size={12} /> Factory Reset User Data
                    </button>
                    </div>
                )}
              </div>
            )}
        </div>
      </main>

      <MobileNavigation 
        currentMode={currentMode} 
        onModeChange={(m) => setCurrentMode(m)}
        isVisible={isHeaderVisible}
      />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Question } from '../types';
import { 
  Map as MapIcon, ChevronRight, Search, Maximize2, Minimize2, X, 
  Filter, AlertTriangle, CheckCircle2, ChevronDown, Layers, Scan,
  BrainCircuit, LayoutTemplate, Volume2, VolumeX
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';
import Quiz from './Quiz'; // Reuse Quiz component for mini-sessions
import { useSpeech } from '../hooks/useSpeech';

// Robust Image Proxy for High Performance & Reliability
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Using wsrv.nl for reliable resizing, webp conversion, and caching
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=1200&q=82&output=webp&il`;
};

interface InteractiveAtlasProps {
  data: Question[];
}

const InteractiveAtlas: React.FC<InteractiveAtlasProps> = ({ data }) => {
  // State Persistence Initialization
  const [selectedImage, setSelectedImage] = useState<string | null>(() => {
    return localStorage.getItem('ot_atlas_selected_image') || null;
  });

  const [isImageExpanded, setIsImageExpanded] = useState(() => {
    return localStorage.getItem('ot_atlas_image_expanded') === 'true';
  });

  const [isQuizMode, setIsQuizMode] = useState(false);

  const [search, setSearch] = useState(() => {
    return localStorage.getItem('ot_atlas_search') || '';
  });

  const [visibleLimit, setVisibleLimit] = useState(24);

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const [showMistakesOnly, setShowMistakesOnly] = useState(() => {
    return localStorage.getItem('ot_atlas_filter_mistakes') === 'true';
  });

  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
        const saved = localStorage.getItem('ot_atlas_filter_categories');
        return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const isMounted = useRef(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  // Mistakes Vault Integration
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  // Persist State Changes
  useEffect(() => {
    if (selectedImage) {
        localStorage.setItem('ot_atlas_selected_image', selectedImage);
    } else {
        localStorage.removeItem('ot_atlas_selected_image');
    }
  }, [selectedImage]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_image_expanded', String(isImageExpanded));
  }, [isImageExpanded]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_search', search);
  }, [search]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_filter_mistakes', String(showMistakesOnly));
  }, [showMistakesOnly]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_filter_categories', JSON.stringify(selectedCategories));
  }, [selectedCategories]);

  // Audio Cleanup
  useEffect(() => {
    if (!selectedImage || isQuizMode) {
        cancel();
    }
  }, [selectedImage, isQuizMode, cancel]);

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Permanently remove all diagrams from your mistakes list?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  // Data Processing: Group questions by Image URL
  const atlasItems = useMemo(() => {
    const imagesMap = new Map<string, Question[]>();

    data.forEach(q => {
      const url = q.questionImage || q.answerImage;
      if (url) {
        if (!imagesMap.has(url)) imagesMap.set(url, []);
        imagesMap.get(url)?.push(q);
      }
    });

    let items = Array.from(imagesMap.entries()).map(([url, questions]) => ({
      url,
      category: questions[0].category,
      related: questions,
      // Enhanced title cleaning
      title: questions[0].questionText
        .replace(/^In the diagram,?\s*/i, '')
        .replace(/^Identify the\s+/i, '')
        .replace(/^Where is the\s+/i, '')
        .replace(/\??$/i, '')
        .trim(),
      hasMistake: questions.some(q => mistakesVault.includes(q.id))
    }));

    // Filtering
    if (showMistakesOnly) items = items.filter(item => item.hasMistake);
    if (selectedCategories.length > 0) items = items.filter(item => selectedCategories.includes(item.category));

    if (search.trim()) {
        const term = search.toLowerCase();
        items = items.filter(item => 
            item.category.toLowerCase().includes(term) || 
            item.related.some(r => r.questionText.toLowerCase().includes(term)) ||
            item.related.some(r => r.answerText.toLowerCase().includes(term))
        );
    }

    return items;
  }, [data, search, showMistakesOnly, selectedCategories, mistakesVault]);

  useEffect(() => {
    setVisibleLimit(24);
  }, [search, showMistakesOnly, selectedCategories]);

  // Close quiz/reset when image changes (Respects initial load)
  useEffect(() => {
    if (isMounted.current) {
        setIsQuizMode(false);
        setIsImageExpanded(false);
    } else {
        isMounted.current = true;
    }
  }, [selectedImage]);

  const activeEntry = useMemo(() => atlasItems.find(i => i.url === selectedImage), [atlasItems, selectedImage]);
  const visibleItems = atlasItems.slice(0, visibleLimit);

  const handleReadAloud = () => {
    if (!activeEntry) return;
    if (isSpeaking && speakingId === 'atlas-summary') {
        cancel();
    } else {
        const points = activeEntry.related.map((p, i) => {
            const label = p.questionText.replace(/^In the diagram,?\s*/i, '').replace(/^Identify the\s+/i, '').replace(/\??$/i, '');
            return `Point ${i + 1}: ${label}. ${p.answerText}`;
        }).join('. ');

        const fullText = `Structure Breakdown for ${activeEntry.title}. ${points}`;
        speak(fullText, 'atlas-summary');
    }
  };

  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Gallery',
        subLabel: `${mistakesVault.length} Active Errors`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) { setSelectedCategories([]); } },
        colorTheme: 'amber'
    }
  ];

  return (
    <div className="h-full flex flex-col bg-slate-50/50 relative">

      {/* 1. Sticky Header Control Bar - High Z-Index to stay above cards */}
      <div className="px-4 py-4 md:px-8 md:py-6 sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200/60 shadow-sm">
        <div className="max-w-7xl mx-auto flex gap-3 md:gap-4 items-center">

            {/* Search Input */}
            <div className="flex-1 relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <Search className="text-slate-400 group-focus-within:text-rose-500 transition-colors" size={18} />
                </div>
                <input 
                    type="text" 
                    placeholder={showMistakesOnly ? "Search errors in diagrams..." : "Search anatomical structures..."} 
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 rounded-xl bg-slate-100/50 border border-slate-200 text-slate-700 font-medium text-sm focus:bg-white focus:border-rose-300 focus:ring-4 focus:ring-rose-100 outline-none transition-all placeholder:text-slate-400"
                />
            </div>

            {/* Filter Toggle */}
            <button 
                onClick={() => setIsFilterOpen(true)}
                className={`h-[46px] px-4 md:px-6 rounded-xl border transition-all flex items-center gap-2 font-bold text-xs uppercase tracking-wider ${
                    selectedCategories.length > 0 || showMistakesOnly 
                    ? 'bg-rose-50 border-rose-200 text-rose-700' 
                    : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                }`}
            >
                <Filter size={16} />
                <span className="hidden md:inline">Filters</span>
                {(selectedCategories.length > 0 || showMistakesOnly) && (
                    <span className="flex h-5 w-5 items-center justify-center rounded-full bg-rose-600 text-[9px] text-white ml-1">
                        {[selectedCategories.length > 0, showMistakesOnly].filter(Boolean).length}
                    </span>
                )}
            </button>
        </div>

        {/* Diagnostic Mode Banner */}
        {showMistakesOnly && (
            <div className="max-w-7xl mx-auto mt-3 animate-in slide-in-from-top-2 fade-in">
                <div className="bg-amber-50 border border-amber-100 rounded-lg px-4 py-2 flex items-center justify-between text-amber-800 shadow-sm">
                    <div className="flex items-center gap-2">
                        <AlertTriangle size={16} className="text-amber-600" />
                        <span className="text-xs font-bold uppercase tracking-wide">Diagnostic Mode Active</span>
                    </div>
                    <span className="text-[10px] font-bold opacity-70">{atlasItems.length} Diagrams Found</span>
                </div>
            </div>
        )}
      </div>

      {/* 2. Main Content Grid */}
      <div className="flex-1 overflow-y-auto px-4 md:px-8 py-6 custom-scrollbar scroll-smooth">
        <div className="max-w-7xl mx-auto pb-32">
            {atlasItems.length > 0 ? (
                <>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 content-visibility-auto">
                    {visibleItems.map((item, idx) => (
                        <div 
                            key={idx} 
                            onClick={() => setSelectedImage(item.url)}
                            className="group cursor-pointer bg-white rounded-2xl border border-slate-100 shadow-card hover:shadow-card-hover hover:-translate-y-1 transition-all duration-300 flex flex-col overflow-hidden relative"
                        >
                            {/* Card Image */}
                            <div className="aspect-[4/3] bg-slate-50 relative overflow-hidden flex items-center justify-center p-4 border-b border-slate-50">
                                <img 
                                    src={cleanImageUrl(item.url)} 
                                    className="max-w-full max-h-full object-contain transition-transform duration-700 group-hover:scale-105" 
                                    alt="Anatomy Diagram" 
                                    loading="lazy" 
                                />

                                {/* Overlay on Hover */}
                                <div className="absolute inset-0 bg-slate-900/0 group-hover:bg-slate-900/5 transition-colors z-10 flex items-center justify-center">
                                    <div className="bg-white/90 backdrop-blur-sm text-slate-900 px-3 py-2 rounded-full font-bold text-[10px] uppercase tracking-widest shadow-lg opacity-0 translate-y-2 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-300 flex items-center gap-2 transform">
                                        <Scan size={14} className="text-rose-500" /> Inspect
