                                </div>

                                <div className="mt-4 pt-3 border-t border-slate-50 flex items-center justify-between text-slate-400">
                                    <span className="text-[10px] font-bold uppercase tracking-wider flex items-center gap-1.5">
                                        <Layers size={14} className="text-slate-300" /> {item.related.length} Features
                                    </span>
                                    <ChevronRight size={14} className="group-hover:translate-x-1 transition-transform text-rose-300" />
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Pagination Button */}
                {visibleLimit < atlasItems.length && (
                    <div className="mt-12 flex justify-center">
                        <button 
                            onClick={() => setVisibleLimit(prev => prev + 24)}
                            className="px-8 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest hover:border-slate-300 hover:bg-slate-50 hover:text-slate-900 transition-all flex items-center gap-2 shadow-sm active:scale-95"
                        >
                            Load More Diagrams <ChevronDown size={14} />
                        </button>
                    </div>
                )}
                </>
            ) : (
                <div className="flex flex-col items-center justify-center py-24 text-center space-y-4 opacity-50">
                    <MapIcon size={48} className="text-slate-300" strokeWidth={1.5} />
                    <p className="font-bold text-slate-400">No Atlas Entries Found</p>
                </div>
            )}
        </div>
      </div>

      {/* 3. Detailed View Modal - Split Screen */}
      {/* Z-Index 300 to stay above Mobile Navigation (z-200) */}
      {activeEntry && (
        <div className="fixed inset-0 z-[300] flex flex-col md:flex-row bg-slate-950/95 backdrop-blur-xl animate-in fade-in duration-300">

          <button 
            onClick={() => setSelectedImage(null)} 
            className="absolute top-4 right-4 z-[310] p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all backdrop-blur-md border border-white/10 group"
          >
            <X size={20} className="group-hover:rotate-90 transition-transform" />
          </button>

          {/* Left Panel: Image (Responsive sizing based on expansion) */}
          <div className={`${isImageExpanded ? 'w-full h-full' : 'h-[40vh] md:h-full md:flex-[1.6]'} bg-slate-900 relative flex items-center justify-center p-4 md:p-12 overflow-hidden shadow-2xl transition-all duration-500`}>
            <div className="absolute inset-0 bg-grid-pattern opacity-5 pointer-events-none"></div>
            <img 
                src={cleanImageUrl(activeEntry.url)} 
                className="max-w-full max-h-full object-contain rounded-lg shadow-2xl" 
                alt="Active Diagram" 
            />

            {/* View Controls */}
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2">
                <button 
                    onClick={() => setIsImageExpanded(!isImageExpanded)}
                    className="bg-black/60 text-white/90 px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest backdrop-blur-md flex items-center gap-2 border border-white/10 hover:bg-white/20 transition-all"
                >
                    {isImageExpanded ? <><Minimize2 size={12} /> Show Info</> : <><Maximize2 size={12} /> Fullscreen Image</>}
                </button>
            </div>
          </div>

          {/* Right Panel: Data Points (Hidden when image expanded) */}
          <div className={`${isImageExpanded ? 'w-0 hidden' : 'flex-1 h-[60vh] md:h-full'} bg-white md:rounded-l-[2rem] overflow-hidden flex flex-col shadow-2xl relative z-10 transition-all duration-500`}>

            {isQuizMode ? (
                // MINI QUIZ MODE
                <div className="flex-1 flex flex-col bg-slate-50">
                    <div className="p-6 border-b border-slate-200 bg-white flex justify-between items-center">
                        <h3 className="font-bold text-slate-800 flex items-center gap-2 text-sm">
                            <BrainCircuit size={18} className="text-rose-500" /> 
                            Quick Practice
                        </h3>
                        <button onClick={() => setIsQuizMode(false)} className="text-xs font-bold uppercase tracking-widest text-slate-400 hover:text-slate-900">
                            Exit Quiz
                        </button>
                    </div>
                    <div className="flex-1 overflow-hidden relative">
                        {/* We reuse the Quiz component but strictly filter for THIS diagram's questions */}
                        <Quiz 
                            data={activeEntry.related} 
                            toggleHeader={() => {}} // No-op, we handle layout manually
                        />
                    </div>
                </div>
            ) : (
                // STANDARD INFO LIST
                <>
                <div className="p-6 md:p-8 border-b border-slate-100 bg-white sticky top-0 z-10">
                <div className="flex items-center gap-2 mb-4">
                    <span className="px-2 py-0.5 bg-rose-50 text-rose-600 rounded text-[9px] font-black uppercase tracking-widest border border-rose-100">
                        {activeEntry.category.split(':')[0]}
                    </span>
                </div>

                <div className="flex justify-between items-start gap-4">
                    <h2 className="text-xl md:text-2xl font-display font-bold text-slate-900 leading-tight">
                        Structure Breakdown
                    </h2>
                    <div className="flex gap-2">
                        <button 
                            onClick={handleReadAloud}
                            className={`w-9 h-9 flex items-center justify-center rounded-lg border transition-all ${isSpeaking && speakingId === 'atlas-summary' ? 'bg-rose-100 border-rose-200 text-rose-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-900'}`}
                            title="Read Description"
                        >
                            {isSpeaking && speakingId === 'atlas-summary' ? <VolumeX size={16} /> : <Volume2 size={16} />}
                        </button>
                        <button 
                            onClick={() => setIsQuizMode(true)}
                            className="px-4 py-2 bg-slate-900 text-white rounded-lg text-[10px] font-bold uppercase tracking-widest flex items-center gap-2 hover:bg-rose-600 transition-all shadow-lg active:scale-95"
                        >
                            <BrainCircuit size={14} /> Practice
                        </button>
                    </div>
                </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar space-y-4 bg-slate-50/50 pb-safe">
                {activeEntry.related.map((point, pIdx) => {
                    const isMistake = mistakesVault.includes(point.id);
                    return (
                        <div key={pIdx} className={`relative p-5 rounded-2xl bg-white border transition-all duration-300 ${isMistake ? 'border-amber-200 ring-1 ring-amber-100 shadow-sm' : 'border-slate-100 hover:border-slate-200 hover:shadow-sm'}`}>
                            <div className="flex justify-between items-start mb-2">
                                <div className="flex items-center gap-3">
                                    <div className={`flex items-center justify-center w-6 h-6 rounded-full text-[10px] font-bold border ${isMistake ? 'bg-amber-50 text-amber-700 border-amber-200' : 'bg-slate-100 text-slate-500 border-slate-200'}`}>
                                        {pIdx + 1}
                                    </div>
                                    <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Point of Interest</span>
                                </div>

                                {isMistake && (
                                    <button 
                                        onClick={(e) => handleResolveMistake(point.id, e)}
                                        className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-50 text-emerald-700 rounded-lg text-[10px] font-black uppercase tracking-wider hover:bg-emerald-100 transition-colors border border-emerald-100"
                                    >
                                        <CheckCircle2 size={12} /> Resolve
                                    </button>
                                )}
                            </div>

                            <div className="pl-9 space-y-2">
                                <p className="text-sm font-bold text-slate-800 leading-snug" dangerouslySetInnerHTML={{ __html: point.questionText.replace(/^In the diagram,?\s*/i, '').replace(/^Identify the\s+/i, '') }} />
                                <div className="relative pl-3 border-l-2 border-rose-200">
                                    <p className="text-sm font-medium text-slate-600" dangerouslySetInnerHTML={{ __html: point.answerText }} />
                                </div>
                            </div>
                        </div>
                    );
                })}

                <div className="text-center py-8">
                    <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-300">End of Record</span>
                </div>
                </div>
                </>
            )}
          </div>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Atlas Filters"
      />
    </div>
  );
};

export default InteractiveAtlas;

import React from 'react';
import { X, Check, Filter, Trash2, AlertTriangle } from 'lucide-react';

export interface FilterOption {
  label: string;
  subLabel?: string;
  icon: React.ElementType;
  isActive: boolean;
  onClick: () => void;
  colorTheme: 'amber' | 'indigo' | 'rose' | 'emerald';
}

interface FilterModalProps {
  isOpen: boolean;
  onClose: () => void;
  categories: string[];
  selectedCategories: string[];
  onToggleCategory: (category: string) => void;
  onClearAll: () => void;
  mainOptions: FilterOption[];
  onWipeVault?: () => void; // Added prop for deleting mistakes
  title?: string;
}

const FilterModal: React.FC<FilterModalProps> = ({
  isOpen,
  onClose,
  categories,
  selectedCategories,
  onToggleCategory,
  onClearAll,
  mainOptions,
  onWipeVault,
  title = "System Filters"
}) => {
  if (!isOpen) return null;

  // Helper for dynamic colors
  const getThemeClasses = (theme: string, active: boolean) => {
    const base = "border-2 transition-all shadow-sm";
    if (!active) return `${base} bg-slate-50 border-slate-100 text-slate-400 hover:border-slate-200`;

    switch (theme) {
      case 'amber': return `${base} bg-amber-50 border-amber-500 text-amber-700 shadow-amber-100`;
      case 'indigo': return `${base} bg-indigo-50 border-indigo-500 text-indigo-700 shadow-indigo-100`;
      case 'emerald': return `${base} bg-emerald-50 border-emerald-500 text-emerald-700 shadow-emerald-100`;
      case 'rose': default: return `${base} bg-rose-50 border-rose-500 text-rose-700 shadow-rose-100`;
    }
  };

  const getIconBg = (theme: string, active: boolean) => {
    if (!active) return "bg-white text-slate-300";
    switch (theme) {
      case 'amber': return "bg-amber-100 text-amber-600";
      case 'indigo': return "bg-indigo-100 text-indigo-600";
      case 'emerald': return "bg-emerald-100 text-emerald-600";
      case 'rose': default: return "bg-rose-100 text-rose-600";
    }
  };

  return (
    <div className="fixed inset-0 z-[400] animate-in fade-in duration-300">
      <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md" onClick={onClose}></div>
      <div className="absolute bottom-0 left-0 right-0 bg-white rounded-t-[3rem] p-6 md:p-10 max-h-[85vh] overflow-y-auto custom-scrollbar animate-in slide-in-from-bottom duration-500 shadow-3xl border-t border-rose-100 pb-safe">

         {/* Header */}
         <div className="flex justify-between items-center mb-8 pb-6 border-b border-slate-100 sticky top-0 bg-white z-10">
            <h3 className="font-black uppercase text-sm text-slate-800 tracking-widest flex items-center gap-2">
              <div className="w-1.5 h-6 bg-rose-600 rounded-full"></div> {title}
            </h3>
            <button onClick={onClose} className="p-3 bg-rose-50 rounded-2xl text-rose-600 transition-colors hover:bg-rose-100 hover:scale-105 active:scale-95">
                <X size={20} />
            </button>
         </div>

         {/* Added pb-32 to prevent sticky footer from covering content */}
         <div className="space-y-8 pb-32">
            {/* Main Options Grid */}
            {mainOptions.length > 0 && (
                <div className={`grid ${mainOptions.length === 1 ? 'grid-cols-1' : 'grid-cols-2'} gap-4`}>
                    {mainOptions.map((opt, idx) => {
                        const Icon = opt.icon;
                        return (
                            <button 
                                key={idx}
                                onClick={opt.onClick}
                                className={`p-6 rounded-[2rem] flex flex-col items-center justify-center gap-3 ${getThemeClasses(opt.colorTheme, opt.isActive)}`}
                            >
                                <div className={`p-3 rounded-full ${getIconBg(opt.colorTheme, opt.isActive)}`}>
                                    <Icon size={24} />
                                </div>
                                <div className="text-center">
                                    <span className="block font-black uppercase text-xs tracking-widest">{opt.label}</span>
                                    {opt.subLabel && <span className="text-[10px] font-bold opacity-60">{opt.subLabel}</span>}
                                </div>
                            </button>
                        );
                    })}
                </div>
            )}

            {/* Category List */}
            <div className="space-y-4">
               <div className="flex items-center justify-between px-2">
                   <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] flex items-center gap-2">
                       <Filter size={12} /> Content Selection
                   </h4>
                   <span className="text-[10px] font-bold text-slate-300 bg-slate-50 px-2 py-1 rounded">
                       {selectedCategories.length > 0 ? selectedCategories.length : 'All'} Active
                   </span>
               </div>

               <div className="grid gap-3">
                  {categories.map(cat => {
                    const isSelected = selectedCategories.includes(cat);
                    return (
                        <button 
                            key={cat} 
                            onClick={() => onToggleCategory(cat)}
                            className={`w-full text-left p-5 rounded-2xl text-[11px] font-bold uppercase transition-all flex items-center justify-between border-2 group active:scale-[0.98] ${isSelected ? 'bg-rose-50 border-rose-500 text-rose-700 shadow-sm' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'}`}
                        >
                          <span className="truncate pr-4">{cat}</span> 

                          <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${isSelected ? 'border-rose-500 bg-rose-500 scale-110' : 'border-slate-200 group-hover:border-slate-300'}`}>
                             {isSelected && <Check size={14} className="text-white" strokeWidth={4} />}
                          </div>
                        </button>
                    );
                  })}
               </div>
            </div>
         </div>

         {/* Footer - Sticky */}
         <div className="pt-4 sticky bottom-0 bg-white pb-safe space-y-3 shadow-[0_-10px_40px_rgba(255,255,255,0.9)]">
            <button 
                onClick={() => { onClearAll(); onClose(); }} 
                className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-rose-600 transition-colors flex items-center justify-center gap-2 active:scale-95"
            >
                <span>Reset & Show All</span>
            </button>

            {onWipeVault && (
                <button 
                onClick={onWipeVault}
                className="w-full py-4 bg-amber-50 text-amber-700 border-2 border-amber-100 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-amber-100 hover:border-amber-200 transition-colors flex items-center justify-center gap-2 active:scale-95"
                >
                <Trash2 size={16} /> Delete Mistakes History
                </button>
            )}
         </div>
      </div>
    </div>
  );
};

export default FilterModal;

import React, { useState, useEffect, useMemo } from 'react';
import Header from './Header';
import Flashcards from './Flashcards';
import Quiz from './Quiz';
import QuestionList from './QuestionList';
import InteractiveAtlas from './InteractiveAtlas';
import MobileNavigation from './MobileNavigation';
import { AppMode, Question } from '../types';

// Import all available chapters
import { questions as ch1 } from '../hooks/data_ch1';
import { questions as ch2 } from '../hooks/data_ch2';
import { questions as ch3 } from '../hooks/data_ch3';
import { questions as ch4 } from '../hooks/data_ch4';
import { questions as ch5 } from '../hooks/data_ch5';
import { questions as ch6 } from '../hooks/data_ch6';
import { questions as ch7 } from '../hooks/data_ch7';
import { questions as ch8 } from '../hooks/data_ch8';
import { questions as ch9 } from '../hooks/data_ch9';
import { questions as ch10 } from '../hooks/data_ch10';
import { questions as ch11 } from '../hooks/data_ch11';
import { questions as ch12 } from '../hooks/data_ch12';
import { questions as ch13 } from '../hooks/data_ch13';
import { questions as ch14 } from '../hooks/data_ch14';
import { questions as ch15 } from '../hooks/data_ch15';
import { questions as ch16 } from '../hooks/data_ch16';
import { questions as ch17 } from '../hooks/data_ch17';

import { Trash2, Activity, ChevronRight, Play, BookOpen, Stethoscope, HeartPulse } from 'lucide-react';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(() => {
    return localStorage.getItem('ot_has_started') === 'true';
  });

  // PERSISTENCE: Load last mode or default to Flashcards
  const [currentMode, setCurrentMode] = useState<AppMode>(() => {
    const savedMode = localStorage.getItem('ot_current_mode');
    return (savedMode as AppMode) || AppMode.FLASHCARDS;
  });

  const [isHeaderVisible, setIsHeaderVisible] = useState(true);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // SAVE EFFECTS
  useEffect(() => {
    localStorage.setItem('ot_current_mode', currentMode);
  }, [currentMode]);

  useEffect(() => {
    localStorage.setItem('ot_has_started', String(hasStarted));
  }, [hasStarted]);

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  // --- ULTIMATE DATA ENGINE ---
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    const sources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...ch12, ...ch13, ...ch14, ...ch15, ...ch16, ...ch17,
        ...userVault
    ];

    const categoryAnswerPools: Record<string, string[]> = {};
    sources.forEach(q => {
        if (!categoryAnswerPools[q.category]) categoryAnswerPools[q.category] = [];
        if (q.answerText && q.answerText.length < 120 && !q.answerText.toLowerCase().includes('all of the above')) {
            categoryAnswerPools[q.category].push(q.answerText);
        }
    });

    sources.forEach(q => {
        // FILTER REMOVED: All questions are now allowed, regardless of quality heuristics
        if (!seenIds.has(q.id)) {
            let finalOptions = q.options ? [...q.options] : [];

            // Auto-Generate Options if missing (Safety Net)
            if (finalOptions.length < 2) {
                const pool = categoryAnswerPools[q.category] || [];
                const randomDistractors = pool
                    .filter(a => a !== q.answerText)
                    .sort(() => 0.5 - Math.random())
                    .slice(0, 3);

                finalOptions = [q.answerText, ...randomDistractors];
                if (finalOptions.length < 2) {
                    finalOptions = [q.answerText, "None of the above", "All of the above", "Structure not visible"];
                }
                // Shuffle newly generated options
                finalOptions.sort(() => 0.5 - Math.random());
            }

            // Ensure correct answer is always in options
            if (!finalOptions.includes(q.answerText)) {
                finalOptions[0] = q.answerText;
            }

            uniqueQuestions.push({ ...q, options: finalOptions });
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  if (!hasStarted) {
    return (
      <div className="min-h-[100dvh] w-full bg-slate-50 flex flex-col items-center justify-center p-6 relative overflow-hidden font-sans text-slate-900">
         {/* Tidy Background */}
         <div className="absolute inset-0 bg-white"></div>
         <div className="absolute top-0 left-0 right-0 h-[60vh] bg-slate-50 rounded-b-[4rem] z-0"></div>

         <div className="relative z-10 w-full max-w-md mx-auto flex flex-col items-center text-center space-y-10 animate-fade-in">

            {/* Logo Section */}
            <div className="w-28 h-28 bg-white rounded-3xl shadow-xl shadow-slate-200 flex items-center justify-center relative cursor-pointer hover:scale-105 transition-transform duration-500" onClick={() => setHasStarted(true)}>
                <div className="absolute inset-0 bg-gradient-to-br from-rose-50 to-slate-50 rounded-3xl opacity-50"></div>
                <HeartPulse size={56} className="text-rose-500 relative z-10" strokeWidth={1.5} />
            </div>

            {/* Typography */}
            <div className="space-y-3">
               <span className="inline-block px-3 py-1 rounded-full bg-slate-100 text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] border border-slate-200">
                  Occupational Therapy
               </span>
               <h1 className="text-4xl md:text-5xl font-black text-slate-900 tracking-tight leading-tight font-display">
                  Anatomy <span className="text-rose-500">&</span><br/>Physiology
               </h1>
            </div>

            {/* Action */}
            <div className="w-full space-y-6">
                <button 
                  onClick={() => setHasStarted(true)}
                  className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs shadow-lg hover:bg-rose-600 hover:shadow-rose-200 transition-all transform active:scale-95 flex items-center justify-center gap-3"
                >
                     <span>Start Session</span>
                     <ChevronRight size={14} />
                </button>

                <div className="flex justify-center items-center gap-8 text-slate-300">
                    <div className="flex flex-col items-center gap-1.5">
                        <BookOpen size={18} />
                        <span className="text-[9px] font-bold uppercase tracking-widest">{allQuestions.length} Items</span>
                    </div>
                    <div className="w-px h-8 bg-slate-200"></div>
                    <div className="flex flex-col items-center gap-1.5">
                        <Stethoscope size={18} />
                        <span className="text-[9px] font-bold uppercase tracking-widest">Clinical</span>
                    </div>
                </div>
            </div>
         </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col font-sans text-slate-900 overflow-hidden fixed inset-0 bg-slate-50">
      {isHeaderVisible && (
        <Header currentMode={currentMode} onModeChange={(m) => setCurrentMode(m)} />
      )}

      {/* Main Content Area */}
      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isHeaderVisible ? 'pt-4 md:pb-6 max-w-7xl px-0 md:px-6' : 'max-w-full'}`}>

        <div className={`w-full h-full rounded-t-[2.5rem] md:rounded-[2.5rem] overflow-hidden shadow-2xl border border-white/50 bg-white/80 backdrop-blur-xl relative z-10 transition-all duration-700 ${!isHeaderVisible ? 'rounded-none border-none bg-white' : ''}`}>

            {currentMode === AppMode.FLASHCARDS && (
              <div className="w-full h-full animate-fade-in pb-28 md:pb-0">
                <Flashcards data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.ATLAS && (
              <div className="w-full h-full animate-fade-in pb-28 md:pb-0">
                <InteractiveAtlas data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.QUIZ && (
              <div className="w-full h-full animate-scale-in pb-28 md:pb-0">
                <Quiz 
                  data={allQuestions} 
                  toggleHeader={setIsHeaderVisible} 
                />
              </div>
            )}

            {currentMode === AppMode.LIST && (
              <div className="w-full h-full overflow-y-auto px-4 py-6 custom-scrollbar pb-32 md:pb-6 animate-fade-in">
                <QuestionList 
                  data={allQuestions}
                />
                {userVault.length > 0 && (
                    <div className="flex justify-center p-12 pb-32">
                    <button onClick={() => confirm("Reset user data?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors flex items-center gap-2">
                        <Trash2 size={12} /> Factory Reset User Data
                    </button>
                    </div>
                )}
              </div>
            )}
        </div>
      </main>

      <MobileNavigation 
        currentMode={currentMode} 
        onModeChange={(m) => setCurrentMode(m)}
        isVisible={isHeaderVisible}
      />
    </div>
  );
};

export default App;
